head.script:
scwin.fromDay;
scwin.toDay;
scwin.tomorrow;

scwin.memJson;
scwin.sUserId;
scwin.sUserNm;
scwin.sUserClsCd;
scwin.sClntNo;
scwin.sClntNm;

scwin.order_chk;
scwin.oldRowValue;
scwin.dateStr1;
scwin.dateStr2;
scwin.tomorrowStr;

scwin.currDay;
scwin.edisndYn;
scwin.gv_loabranCd;

scwin.initOnloadFlag;

scwin.comboRtnFlag01;
scwin.interval01;

scwin.udc_objNm;

scwin.gridColIdx;
scwin.gridRowIdx;

scwin.excelUploadFlag;

scwin.onpageload = function() {
    //전역변수값 셋팅함수.
	scwin.initSetVal();

    const codeOptions = [ 
        {
            method: "getLuxeComboData", 
            param1: "WorkImplementEBC", 
            param2: "retriveLobran2CodeList",
            compID: "acb_lobranCd" 
        }
    ];
    $c.data.setGauceUtil(codeOptions, scwin.commonCodeCallBack01);

    scwin.interval01 = setInterval(async function() {
        if(scwin.comboRtnFlag01 == true) {
            clearInterval(scwin.interval01);
            //초기화
  	        scwin.f_OnLoad();
        }
    }, 300);
};

scwin.initSetVal = function() {
    scwin.fromDay = $c.date.getServerDateTime("yyyyMMdd");
    scwin.toDay = $c.date.addDate(scwin.fromDay, 7);
    scwin.tomorrow = $c.date.addDate(scwin.fromDay, 1);

    scwin.memJson = $c.data.getMemInfo();
    scwin.sUserId = scwin.memJson.userId;
    scwin.sUserNm = scwin.memJson.userNm;
    scwin.sUserClsCd = scwin.memJson.userClsCd;
    scwin.sClntNo = scwin.memJson.clntNo;
    scwin.sClntNm = scwin.memJson.clntNm;

    scwin.order_chk = "N";
    scwin.oldRowValue = 0;
    scwin.dateStr1 = scwin.fromDay;
    scwin.dateStr2 = scwin.toDay;
    scwin.tomorrowStr = scwin.tomorrow;

    scwin.currDay = "";
    scwin.edisndYn = "0";
    scwin.gv_loabranCd = scwin.memJson.loUpperLobranCd;

    scwin.comboRtnFlag01 = false;
    scwin.initOnloadFlag = true;

    scwin.excelUploadFlag = false;
};

scwin.commonCodeCallBack01 =  function() {
    scwin.comboRtnFlag01 = true;
};


scwin.onUdcCompleted = function () {
    ed_begintrainWorkPlaceCd.bind("onkeyup", function(e){
        ed_begintrainWorkPlaceCd.setValue(ed_begintrainWorkPlaceCd.getValue().toUpperCase());
    });

    ed_endtrainWorkPlaceCd.bind("onkeyup", function(e){
        ed_endtrainWorkPlaceCd.setValue(ed_endtrainWorkPlaceCd.getValue().toUpperCase());
    });

    ed_lineCd.bind("onkeyup", function(e){
        ed_lineCd.setValue(ed_lineCd.getValue().toUpperCase());
    });
};
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad =  function() {
    ed_reqDt.setValue(scwin.dateStr1);
	ed_reqDtTo.setValue(scwin.dateStr1);
	acb_lobranCd.focus();

    $c.gus.cfDisableBtn([btn_save]);

	//배차점소
	acb_lobranCd.setValue(scwin.gv_loabranCd);    

    rd_upload.setValue("0");
};


//-------------------------------------------------------------------------
//  조회
//-------------------------------------------------------------------------
scwin.f_qeryList = async function() {
    let ret = await $c.gus.cfValidate([ed_reqDt,ed_reqDtTo]);
    if (!ret) {	// 신청일자, 출발역
  		return;
	}
	if (( $c.gus.cfIsNull(ed_begintrainWorkPlaceCd.getValue()) || ed_begintrainWorkPlaceCd.getValue() == "")
			&& ($c.gus.cfIsNull(ed_endtrainWorkPlaceCd.getValue())|| ed_endtrainWorkPlaceCd.getValue() == "") ){
		await $c.win.alert("출발역 또는 도착역  둘중에 하나는 필수로 입력 하셔야 됩니다!!!");
		return false;
	}	

    dma_QueryCondition.set("lobranCd", acb_lobranCd.getValue());   // 신청일자From
    dma_QueryCondition.set("reqDt", ed_reqDt.getValue().trim());   // 신청일자From
    dma_QueryCondition.set("reqDtTo", ed_reqDtTo.getValue().trim());   // 신청일자To
    dma_QueryCondition.set("sendDt", ed_sendDt.getValue().trim());   // 발송일자From
    dma_QueryCondition.set("sendDtTo", ed_sendDtTo.getValue().trim());   // 발송일자To    
    dma_QueryCondition.set("dptStnCd", ed_begintrainWorkPlaceCd.getValue().trim());     // 출발역
    dma_QueryCondition.set("arvStnCd", ed_endtrainWorkPlaceCd.getValue().trim());        // 도착역
    dma_QueryCondition.set("regId", em_alloccarPicId.getValue().trim());   // 신청일자From
    dma_QueryCondition.set("clntNo", ed_bilgClntNo.getValue().trim());   // 신청일자To
    dma_QueryCondition.set("lineCd", ed_lineCd.getValue().trim());   // 신청일자From
    dma_QueryCondition.set("siz", acb_siz.getValue());   // 신청일자To    
    dma_QueryCondition.set("typ", acb_typ.getValue());     // 출발역
    dma_QueryCondition.set("fullEmptyClsCd", acb_ef.getValue());     // 출발역    
    dma_QueryCondition.set("dptArvYn", acb_dptArvYn.getValue());        // 도착역    
    dma_QueryCondition.set("cntrNos", ed_cntrNo.getValue());

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_RetrieveRailroadWorkPlan);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_RetrieveRailroadWorkPlan_submitdone();
    }
};

scwin.sbm_RetrieveRailroadWorkPlan_submitdone = async function (e) {
    $c.gus.cfEnableObjects([btn_save]);
    scwin.initOnloadFlag = false;

    if(ds_RailroadWorkPlan.getRowCount() > 0){
		grp_totalRows.setStyle("display", "");
        tbx_totalRows.setValue(ds_RailroadWorkPlan.getRowCount());

        //최초 조회시 focus 셋팅위해 추가.
        //기존에 cell 클릭한 케이스가 존재하면, 해당 컬럼 위치의 젤 처음 row 로 셋팅하고
        //미존재하면 0,0 index 로 셋팅. 
        var colIdx = scwin.gridColIdx;
        if(colIdx == undefined || colIdx == null || colIdx == "") {
            colIdx = 0;
        }
        gr_RailroadWorkPlan.setFocusedCell(0, colIdx);
	}else{
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}
};

//그리드 cell 클릭시.(cell 클릭시 컬럼 및 row index 가져오기 위해.)
scwin.gr_RailroadWorkPlan_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.gridColIdx = columnIndex;
    scwin.gridRowIdx = rowIndex;
};


scwin.gr_RailroadWorkPlan_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    var condition ="?";

	var dptStnCd = ds_RailroadWorkPlan.getCellData(rowIndex, "dptStnWrkPlCd");
	var arvStnCd = ds_RailroadWorkPlan.getCellData(rowIndex, "arvStnWrkPlCd");
	var onReqDt = ds_RailroadWorkPlan.getCellData(rowIndex, "reqDt");
	var cntrNo = ds_RailroadWorkPlan.getCellData(rowIndex, "cntrNo");
	var frtcarNo = ds_RailroadWorkPlan.getCellData(rowIndex, "frtcarNo");
	var btCls = "1";        // 적재등록에 자동추가 위해 넘겨줄 값..

	if( columnId == "reqDt" ) {
	    if(ds_RailroadWorkPlan.getCellData(rowIndex, "adminfrtcarYn")!= "2"){
			//condition += "dptStnCd="+dptStnCd+"&arvStnCd="+arvStnCd+"&onReqDt="+onReqDt+"&cntrNo="+cntrNo+"&frtcarNo="+frtcarNo+"&btCls="+btCls;

			//strOrderDetailUrl = "/ds/op/wrkrslts/railroadwrkrslts/op_205_01_01b.jsp";
			//cfTabMenuUpdate( strOrderDetailUrl+condition , "적재내역등록") ;

            var pgmId = "op_205_01_01b.xml";
            var strCertiNoDetailUrl = "/ui/ds/op/wrkrslts/railroadwrkrslts/" + pgmId;
            var title = "적재내역등록"

            var paramObj = {
                dptStnCd : dptStnCd,
                arvStnCd : arvStnCd,
                onReqDt : onReqDt,
                cntrNo : cntrNo,
                frtcarNo : frtcarNo,
                btCls : btCls
            }

            $c.win.openMenu(title, strCertiNoDetailUrl, pgmId, paramObj);   
	    }else{
	    	//condition += "dptStnCd="+dptStnCd+"&arvStnCd="+arvStnCd+"&onReqDt="+onReqDt+"&cntrNo="+cntrNo+"&frtcarNo="+frtcarNo+"&btCls="+btCls;

	    	//strOrderDetailUrl = "/ds/op/wrkplan/railroadwrkplan/op_203_01_09b.jsp";
	    	//cfTabMenuUpdate( strOrderDetailUrl+condition , "BT컨테이너적재등록") ;

            var pgmId = "op_203_01_09b.xml";
            var strCertiNoDetailUrl = "/ui/ds/op/wrkplan/railroadwrkplan/" + pgmId;
            var title = "저수요컨테이너적재등록"
            option ={}
            option.mdiTitle = "BT컨테이너적재등록"
            var paramObj = {
                dptStnCd : dptStnCd,
                arvStnCd : arvStnCd,
                onReqDt : onReqDt,
                cntrNo : cntrNo,
                frtcarNo : frtcarNo,
                btCls : btCls
            }

            $c.win.openMenu(title, strCertiNoDetailUrl, pgmId, paramObj, option);     
	    }	
	}
};


//-------------------------------------------------------------------------
// 저장버튼 처리 
//-------------------------------------------------------------------------
scwin.isGrdDupDataFlag = async function (grdObj, strGrdNm, colObj) {
    var sRtn = false;

    let hVal = "",
        tHval = "";
    let dataListObj = $p.getComponentById(grdObj.getDataList());

    // alert 출력을 위해서 헤더 정보값을 만든다
    for (let idx in colObj) {
        hVal = grdObj.getHeaderValue(grdObj.getHeaderID(grdObj.getColumnIndex(colObj[idx]))) || "이름없음";
        hVal = hVal.replace(/<[^>]*>/gi, "").replace(" ","");
        if(tHval.length == 0) {
            tHval = hVal;
        } else {
            tHval = tHval + ", " + hVal;
        }
    }

    // 배열에 컬럼값들 합쳐서 담기.
    let colData,rowData;
    let colChkAllData = [];
    for(var i=0;i<dataListObj.getRowCount();i++) {
        rowData = "";
        for (let idx in colObj) {
            colData = dataListObj.getCellData(i, colObj[idx]);
            if(idx == 0) {
                rowData = colData;
            } else {
                rowData = rowData + colData;
            }  
        }
        colChkAllData.push(rowData);
    }

    // 데이터 중복 체크
    const result = {};
    let dupIdx;
    sRtn =  colChkAllData.some((value, key) => {
                result[value] = (result[value] || 0) + 1;
                if (result[value] > 1) {
                    dupIdx = key+1;
                    return true;
                }
            });

    if (sRtn && (dupIdx != undefined && dupIdx != null && dupIdx != "")) {
        await $c.win.alert(strGrdNm + "의 " + dupIdx + "번째 데이터에서 " + tHval + "은(는) 중복될 수 없습니다.");
        scwin.sleep(50).then(function () {
            /*
            if(gr_oilUnitPrice.getFocusedColumnID() != undefined && gr_oilUnitPrice.getFocusedColumnID() != null && gr_oilUnitPrice.getFocusedColumnID() != "") {
                grdObj.setFocusedCell(dupIdx-1, gr_oilUnitPrice.getFocusedColumnID());
            } else {
                grdObj.setFocusedCell(dupIdx-1, colObj[colObj.length-1]);
            }
            */
            grdObj.setFocusedCell(dupIdx-1, colObj[colObj.length-1]), true;           
        });
    }

    return sRtn;
};


scwin.f_Save = async function() {
    if (ds_RailroadWorkPlan.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049,["변경사항"]);
        return;
    }

	for(var i=0; i< ds_RailroadWorkPlan.getRowCount(); i++) {
		if(ds_RailroadWorkPlan.getRowStatus(i) == "C" || ds_RailroadWorkPlan.getRowStatus(i) == "U") {
			if(ds_RailroadWorkPlan.getCellData(i,"cntrNo") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["컨테이너번호"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "cntrNo");
				   return false;				
			}	
			if(ds_RailroadWorkPlan.getCellData(i,"dptStnWrkPlNm") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["출발역"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "dptStnWrkPlNm");
				   return false;				    				
			}	
			if(ds_RailroadWorkPlan.getCellData(i,"odrNo") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["오더번호"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "odrNo");
				   return false;				    				
			}
			if(ds_RailroadWorkPlan.getCellData(i,"frtcarNo") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["화차번호"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "frtcarNo");
				   return false;				    				
			}		
			if(ds_RailroadWorkPlan.getCellData(i,"clntNm") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["화주명"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "clntNm");
				   return false; 				
			}		
			if(ds_RailroadWorkPlan.getCellData(i,"vsslNm") == "") {
				   await $c.gus.cfAlertMsg("["+(i+1)+"번째 줄]"+MSG_CM_ERR_002,["모선명"]);
                   gr_RailroadWorkPlan.setFocusedCell(i, "vsslNm");
				   return false; 				
			}												
		}
	}    

    let ret = await $c.gus.cfValidate([gr_RailroadWorkPlan]);
	if(!ret) {
        return false;
    }

    ret = await scwin.isGrdDupDataFlag(gr_RailroadWorkPlan, "철송내역", ["dptStnWrkPlNm", "cntrNo", "odrNo"])
    if(ret) {
        return false;
    }

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
	if(confirmResult) {  

	    //tr_SaveRailroadWorkPlan.Post();
        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_SaveRailroadWorkPlan);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            await scwin.sbm_SaveRailroadWorkPlan_submitdone();
        }


        scwin.order_chk = "N";
    }
};

scwin.sbm_SaveRailroadWorkPlan_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_qeryList();
};

//-------------------------------------------------------------------------
//  행추가  처리 
//-------------------------------------------------------------------------
scwin.f_inputGridAddrow = function() {
    if(scwin.initOnloadFlag) {
        return;
    }

    var nRow = ds_RailroadWorkPlan.getRowCount();

    ds_RailroadWorkPlan.insertRow(nRow);
    ds_RailroadWorkPlan.setCellData(nRow,"reqDt", scwin.dateStr1);
    ds_RailroadWorkPlan.setCellData(nRow,"dptStnWrkPlCd", ed_begintrainWorkPlaceCd.getValue());
    ds_RailroadWorkPlan.setCellData(nRow,"dptStnWrkPlNm", ed_begintrainWorkPlaceNm.getValue());
    ds_RailroadWorkPlan.setCellData(nRow,"adminfrtcarYn", '3');

    //발송여부
    ds_RailroadWorkPlan.setCellData(nRow,"dptArvYn", '0');
    //중량
    ds_RailroadWorkPlan.setCellData(nRow,"wt", 0);

    if(ed_endtrainWorkPlaceCd.getValue() != "") {
        ds_RailroadWorkPlan.setCellData(nRow,"arvStnWrkPlCd", ed_endtrainWorkPlaceCd.getValue());
        ds_RailroadWorkPlan.setCellData(nRow,"arvStnWrkPlNm", ed_endtrainWorkPlaceNm.getValue());			
    }

    ds_RailroadWorkPlan.setRowPosition(nRow);
};

//행삭제 버튼 클릭시
scwin.f_rowDel = function() {
    if(scwin.initOnloadFlag) {
        return;
    }

    //그리드에 매핑된 dataList의 row가 신규행이면 삭제하고 아니면 삭제마크처리.
    if(ds_RailroadWorkPlan.getRowStatus(ds_RailroadWorkPlan.getRowPosition()) == "C") {
        ds_RailroadWorkPlan.removeRow(ds_RailroadWorkPlan.getRowPosition());
    } else {
        ds_RailroadWorkPlan.deleteRow(ds_RailroadWorkPlan.getRowPosition());
    }
};

//취소 버튼 클릭시
scwin.f_cancel = function() {
    if(scwin.initOnloadFlag) {
        return;
    }

    //그리드에 매핑된 dataList rowIdx 미존재시 이전에 클릭했던 rowIdx 셋팅처리.
    if(ds_RailroadWorkPlan.getRowPosition() == null) {
        ds_RailroadWorkPlan.setRowPosition(scwin.gridRowIdx);
    }

    $c.data.undoRow(ds_RailroadWorkPlan, "Y");
};

//그리드에 매핑된 dataList rowStatus 가 변경시.
scwin.ds_RailroadWorkPlan_onrowstatuschange = function (info) {
    //해당 ROW 수정 후 삭제처리시
    if(info[0].oldRowStatus == "U") {
        if(info[0].newRowStatus == "D") {
            $c.data.undoRow(ds_RailroadWorkPlan, "Y");
            ds_RailroadWorkPlan.deleteRow(info[0].rowIndex);
        }
    }
};




//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(grp_search,null);
	ed_reqDt.focus();
	ed_reqDt.setValue(scwin.dateStr1);	
	ed_reqDtTo.setValue(scwin.dateStr1);
};



//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (callObj, inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
	    await scwin.f_openCommonPopUp(callObj, disGubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
	else {
	    await scwin.f_openCommonPopUp(callObj, disGubun, '', pVal, 'T', 'T');
    }
};



//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (callObj,disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
	var rtnList= new Array();  // 공통POP-UP -> 요청화면 
    var pWhere;
    scwin.udc_objNm = callObj.org_id;

	switch (disGubun)
  	{

  		case 1:   // 출발역 역명 팝업	
            if(pCode != null && pCode != undefined && pCode != "") {
                pCode = ed_begintrainWorkPlaceCd.getValue();
            }

            if(pName != null && pName != undefined && pName != "") {
                pName = ed_begintrainWorkPlaceNm.getValue();
            }

            ed_begintrainWorkPlaceCd.setValue("");
            ed_begintrainWorkPlaceNm.setValue("");

            callObj.setSelectId("retrieveTrainWorkPlace");
  			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc	// XML상의 SELECT ID	
  									,pCode					// 화면에서의 ??? Code Element의	Value
  									,pName					// 화면에서의 ??? Name Element의	Value
  									,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  									,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  									,null					// Title순서	
  									,null					// 보여주는 각 컬럼들의 폭	
  									,null					// 컬럼중에서 숨기는	컬럼 지정	
  									,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  									,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
  									,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
  									,null					// 윈도우 위치 Y좌표	
  									,null					// 윈도우 위치 X좌표
  									,null					// 중복체크여부	("F")
  									,pAllSearch					// 전체검색허용여부	("F")
