scwin.f_retrieveCntrBasisInfo = async function(cntrNo) {
    if(!$c.gus.cfIsNull(cntrNo)){

        dma_condCntrBasisInfo.set("cntrNo", cntrNo);
        dma_condCntrBasisInfo.set("odrNo", "");
        dma_condCntrBasisInfo.set("transWrkIndictNo", "");
        dma_condCntrBasisInfo.set("wrkStDt", ed_reqDt.getValue());
        dma_condCntrBasisInfo.set("dptWrkPlCd", ed_begintrainWorkPlaceCd.getValue());
        dma_condCntrBasisInfo.set("arvWrkPlCd", ed_endtrainWorkPlaceCd.getValue());

        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_retrieveCntrBasisInfo);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            await scwin.sbm_retrieveCntrBasisInfo_submitdone();
        }
    }
};


scwin.sbm_retrieveCntrBasisInfo_submitdone = async function() {
    if(ds_cntrBasisInfoResult.getRowCount() > 0){	
		scwin.f_addCntrBasisInfo( ds_RailroadWorkPlan.getRowPosition() );
	}
};


scwin.f_addCntrBasisInfo = function(row) {
    ds_RailroadWorkPlan.setCellData(row,"odrNo", ds_cntrBasisInfoResult.getCellData(0,"odrNo"));
    ds_RailroadWorkPlan.setCellData(row,"lineCd", ds_cntrBasisInfoResult.getCellData(0,"lineCd")); 	  
    ds_RailroadWorkPlan.setCellData(row,"cntrSizCd", ds_cntrBasisInfoResult.getCellData(0,"cntrSizCd"));
    ds_RailroadWorkPlan.setCellData(row,"cntrTypCd", ds_cntrBasisInfoResult.getCellData(0,"cntrTypCd"));
    ds_RailroadWorkPlan.setCellData(row,"sizty", ds_cntrBasisInfoResult.getCellData(0,"cntrSizCd") + ds_cntrBasisInfoResult.getCellData(0,"cntrTypCd"));
    ds_RailroadWorkPlan.setCellData(row,"vsslCd", ds_cntrBasisInfoResult.getCellData(0,"vsslCd"));
    ds_RailroadWorkPlan.setCellData(row,"vsslNm", ds_cntrBasisInfoResult.getCellData(0,"vsslNm"));
    ds_RailroadWorkPlan.setCellData(row,"portcnt", ds_cntrBasisInfoResult.getCellData(0,"portcnt"));	  
    ds_RailroadWorkPlan.setCellData(row,"clntNm", ds_cntrBasisInfoResult.getCellData(0,"bilgClntNm"));
    ds_RailroadWorkPlan.setCellData(row,"clntNo", ds_cntrBasisInfoResult.getCellData(0,"bilgClntNo"));
    ds_RailroadWorkPlan.setCellData(row,"realClntNm", ds_cntrBasisInfoResult.getCellData(0,"realClntNm"));
    ds_RailroadWorkPlan.setCellData(row,"blNo", ds_cntrBasisInfoResult.getCellData(0,"blNo"));
    ds_RailroadWorkPlan.setCellData(row,"bookingNo", ds_cntrBasisInfoResult.getCellData(0,"bookingNo"));

    if ("C2" == ds_cntrBasisInfoResult.getCellData(0,"odrNo").substring(1,3)){
        ds_RailroadWorkPlan.setCellData(row,"blBk", ds_cntrBasisInfoResult.getCellData(0,"blNo"));
    }else{
        ds_RailroadWorkPlan.setCellData(row,"blBk", ds_cntrBasisInfoResult.getCellData(0,"bookingNo"));
    }        

    if(scwin.gv_loabranCd !="4BB"){	  
        ds_RailroadWorkPlan.setCellData(row,"arvWrkPlCd", ds_cntrBasisInfoResult.getCellData(0,"arvWrkPlCd"));
        ds_RailroadWorkPlan.setCellData(row,"arvWrkPlNm", ds_cntrBasisInfoResult.getCellData(0,"arvWrkPlNm"));
    }	
    ds_RailroadWorkPlan.setCellData(row,"fullEmptyClsCd", ds_cntrBasisInfoResult.getCellData(0,"fullEmptyClsCd"));		
};


