//엑셀 다운로드 처리.
scwin.f_Excel = function() {
    if(scwin.initOnloadFlag) {
        return;
    }

    gr_RailroadWorkPlan.removeColumnClass("alngpierDt", "cur-df");

    const options = {
        fileName: "컨테이너적재내역.xlsx",
        sheetName : "컨테이너적재내역"
    };
    $c.data.downloadGridViewExcel(gr_RailroadWorkPlan, options);


    gr_RailroadWorkPlan.setColumnClass("alngpierDt", "underline cur-df");
};

//엑셀 업로드 처리.
scwin.f_ExcelUp = async function() {
    if(scwin.initOnloadFlag) {
        return;
    }

    ds_RailroadWorkPlanExcelUp.removeAll();

    var options = {
        startRowIndex: 1,
        //headerExist: 1,
        type: 1
    }

    if (udc_topGrd.getUpExt() == "1") {
        options.skipSpace = "1";           // 공백무시 여부(1이면 무시 0이면 포함) 
        options.hidden = "0";              // 왼쪽히든값유무(미포함)
        options.fillHidden = "0";          // 오른쪽히든값유무(무시)
        options.startRowIndex = 1;        
        await $c.data.uploadGridViewCSV(gr_RailroadWorkPlanExcelUp, options);
    } else {
        await $c.data.uploadGridViewExcel(gr_RailroadWorkPlanExcelUp, options);
    }

};

