//그리드 cell 수정후 focust out 시
scwin.gr_RailroadWorkPlan_onafteredit = async function (rowIndex, columnIndex, value) {
    await scwin.gr_RailroadWorkPlan_OnExit(rowIndex, columnIndex, value);
};

scwin.gr_RailroadWorkPlan_OnExit = async function (rowIndex, columnIndex, value) {

    var colid = gr_RailroadWorkPlan.getColumnID(columnIndex);

    //출발역
    if( colid == "dptStnWrkPlNm" ) {
	    await scwin.f_openCommonPopUp(udc_grid_dptStnWrkPlNm,4, '', '', 'T','T');
	}
    //도착역
    else if(colid == "arvStnWrkPlNm" ){
		await scwin.f_openCommonPopUp(udc_grid_arvStnWrkPlNm,5, '', '', 'T','T');
	}
    //화주명
    else if(colid == "clntNm" ){
		await scwin.f_openCommonPopUp(udc_grid_clntNm,7, '', '', 'T','T');
	}
    //포트
    else if(colid == "portCd" ){
		await scwin.f_openCommonPopUp(udc_grid_portCd,8, '', '', 'T','T');
	}
    //모선명
    else if(colid == "vsslNm" ){
		await scwin.f_openCommonPopUp(udc_grid_vsslNm,9, '', '', 'T','T');
	}
    //컨테이너번호
    else if(colid == "cntrNo" ){
		await scwin.f_retrieveCntrBasisInfo(ds_RailroadWorkPlan.getCellData(rowIndex,"cntrNo"));
	}
    //하차지
    else if(colid == "arvWrkPlNm" ){
		await scwin.f_openCommonPopUp(udc_grid_arvWrkPlNm,11, '', '', 'T','T');
	} 
    else if(colid == "wt"){
        if(ds_RailroadWorkPlan.getCellData( rowIndex, "wt") == ""){
            ds_RailroadWorkPlan.setCellData( rowIndex, "wt", "0");
        }
    }
};


